<?php namespace App\Repositories\Assessment;use App\Repositories\BaseRepository;use App\Models\Assessment\Exam;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class ExamRepository extends BaseRepository{    public function __construct(Exam $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function findByExamType(int $examTypeId): Collection    {        return $this->findByField('exam_type_id', $examTypeId);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function getUpcomingExams(): Collection    {        return $this->query()->where('start_date', '>=', now())->orderBy('start_date', 'asc')->get();    }    public function getOngoingExams(): Collection    {        return $this->query()->where('start_date', '<=', now())->where('end_date', '>=', now())->get();    }    public function getCompletedExams(): Collection    {        return $this->query()->where('end_date', '<', now())->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('start_date', [$startDate, $endDate])->orWhereBetween('end_date', [$startDate, $endDate])->get();    }    public function searchExams(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function publishResult(int $examId): bool    {        return $this->update($examId, ['result_published' => true, 'result_published_at' => now()]);    }}